INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('wakakusayama-yamayaki', 'Wakakusayama Yamayaki', '若草山焼き', 'Nara', 'Nara', 'kansai', 1, '01-25', '01-25', '["01-25"]', '["fire","traditional"]', 'The hillside of Mt. Wakakusa is set ablaze in a spectacular controlled burn, preceded by fireworks. A dramatic winter event combining ancient ritual with modern spectacle.', '奈良の冬の風物詩。若草山全体に火を放ち、花火も打ち上げられる。', 200000, 'JR Nara Station, 20 min walk', 34.6891, 135.8477, 'Arrive early for a good viewing spot along Nara Park. The fireworks start around 6:15 PM.', 'https://www.pref.nara.jp/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('dondoyaki-saga', 'Dondoyaki Fire Festival', 'どんど焼き', 'Saga', 'Saga', 'kyushu', 1, '01-14', '01-14', '["01-14"]', '["fire","traditional"]', 'New Year decorations and old charms are burned in a large bonfire. A purification ritual marking the end of the New Year celebrations.', '正月飾りを焚き上げる伝統行事。無病息災を祈る。', 15000, 'JR Saga Station', 33.2635, 130.3009, 'Bring your old New Year decorations to be burned. Mochi roasted over the fire is said to bring good health.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('somin-sai', 'Somin-sai Naked Festival', '蘇民祭', 'Oshu', 'Iwate', 'tohoku', 1, '01-31', '01-31', '["01-31"]', '["traditional","fire"]', 'One of Japan''s most extreme winter festivals where men wearing only loincloths compete for sacred charms in freezing temperatures at Kokuseki-ji Temple.', '極寒の中、裸の男たちが護符を奪い合う奇祭。黒石寺で行われる。', 8000, 'JR Mizusawa Station, then taxi 20 min', 39.0875, 141.1619, 'Extremely cold - dress warmly if spectating. The main event starts late at night.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('tamaseseri', 'Tamaseseri Festival', '玉せせり', 'Fukuoka', 'Fukuoka', 'kyushu', 1, '01-03', '01-03', '["01-03"]', '["traditional"]', 'Nearly naked men compete to grab a sacred wooden ball at Hakozaki Shrine. The team that wins predicts whether the year will bring good fishing or farming.', '裸の男たちが木の玉を奪い合う正月行事。筥崎宮で開催。', 50000, 'Fukuoka Metro Hakozaki-Miyamae Station', 33.6192, 130.4253, 'Held on January 3rd every year. Great way to experience traditional New Year energy.', 'https://www.hakozakigu.or.jp/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('sagicho-shiga', 'Sagicho Matsuri', '左義長まつり', 'Omihachiman', 'Shiga', 'kansai', 1, '01-14', '01-15', '["01-14","01-15"]', '["fire","traditional"]', 'Elaborate floats decorated with food ingredients are paraded through the old merchant town before being set on fire in a dramatic climax.', '食材で飾った山車を曳き回した後、勇壮に火をつける近江八幡の奇祭。', 100000, 'JR Omihachiman Station, 15 min bus', 35.1286, 136.0976, 'The parade is on the first day; the fires on the second. Both are worth seeing.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('asahikawa-winter', 'Asahikawa Winter Festival', '旭川冬まつり', 'Asahikawa', 'Hokkaido', 'hokkaido', 1, '01-28', '02-02', '["01-28"]', '["snow","modern"]', 'Features some of the world''s largest snow sculptures, ice slides, and winter activities in Hokkaido''s second largest city.', '巨大雪像が並ぶ旭川の冬の祭典。氷の滑り台なども人気。', 1000000, 'JR Asahikawa Station, 10 min walk', 43.7706, 142.3650, 'Less crowded than Sapporo Snow Festival. Combined trip recommended.', 'https://www.city.asahikawa.hokkaido.jp/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('usokae-dazaifu', 'Usokae Bullfinch Exchange', 'うそ替え神事', 'Dazaifu', 'Fukuoka', 'kyushu', 1, '01-07', '01-07', '["01-07"]', '["traditional"]', 'Participants exchange wooden bullfinch bird figures in darkness, hoping to receive a lucky golden one. A unique Shinto tradition at Dazaifu Tenmangu.', '暗闘の中で木彫りの鷽を交換し、金の鷽を引き当てると幸運が訪れる。', 30000, 'Nishitetsu Dazaifu Station, 5 min walk', 33.5194, 130.5350, 'Arrive by evening. The exchange ceremony happens after dark.', 'https://www.dazaifutenmangu.or.jp/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('hirosaki-snow-lantern', 'Hirosaki Snow Lantern Festival', '弘前城雪燈籠まつり', 'Hirosaki', 'Aomori', 'tohoku', 1, '01-31', '02-02', '["01-31"]', '["snow","lantern"]', 'Snow lanterns and miniature snow houses illuminate Hirosaki Castle Park in a magical winter display.', '弘前城公園に雪燈籠やミニかまくらが並ぶ冬の幻想的イベント。', 250000, 'JR Hirosaki Station, 15 min bus', 40.6072, 140.4636, 'Best viewed after dark when the lanterns are lit. Combine with Hirosaki Castle visit.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('tsunan-snow-carnival', 'Tsunan Snow Carnival', '津南雪まつり', 'Tsunan', 'Niigata', 'chubu', 1, '01-31', '01-31', '["01-31"]', '["snow","lantern","modern"]', 'Thousands of sky lanterns are released into the night sky over snowy mountains, creating a breathtaking scene reminiscent of a Thai lantern festival.', '雪原からスカイランタンを打ち上げる幻想的な冬の祭典。', 20000, 'JR Tsunan Station', 36.9281, 138.6536, 'Sky lantern release requires advance ticket purchase. Sells out quickly.', '', 1, '2026-03-29T00:00:00Z');

