INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('setsubun-yoshida', 'Yoshida Shrine Setsubun', '吉田神社節分祭', 'Kyoto', 'Kyoto', 'kansai', 2, '02-02', '02-04', '["02-03"]', '["fire","traditional"]', 'One of Kyoto''s largest Setsubun celebrations with a dramatic bonfire ritual where old talismans are burned. Hundreds of stalls line the approach.', '京都最大級の節分祭。火炉祭で古いお札を焚き上げる。', 500000, 'Kyoto City Bus to Kyodai-Seimon-mae', 35.0233, 135.7897, 'The bonfire (karosai) on Feb 3 evening is the highlight. Very crowded - arrive early.', 'https://www.yoshidajinja.com/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('iwate-snow-festival', 'Iwate Snow Festival', 'いわて雪まつり', 'Shizukuishi', 'Iwate', 'tohoku', 2, '02-07', '02-11', '["02-08"]', '["snow","modern"]', 'Features snow and ice sculptures, snow slides, fireworks, and stage performances in a snowy mountain setting.', '小岩井農場で開催される雪像・氷像の祭典。花火やステージも。', 300000, 'JR Shizukuishi Station, shuttle bus', 39.7536, 140.9750, 'Evening illumination and fireworks on weekends are spectacular.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('nagasaki-lantern', 'Nagasaki Lantern Festival', '長崎ランタンフェスティバル', 'Nagasaki', 'Nagasaki', 'kyushu', 2, '02-01', '02-15', '["02-01"]', '["lantern","modern"]', 'Around 15,000 Chinese lanterns illuminate Nagasaki''s Chinatown and surrounding areas during the Chinese New Year period. Dragon dances and acrobatic performances.', '約15,000個のランタンが長崎を彩る中国の旧正月イベント。', 1000000, 'JR Nagasaki Station, tram to Chinatown', 32.7445, 129.8790, 'The event spans 2 weeks around Chinese New Year. Evenings are the most atmospheric.', 'https://www.at-nagasaki.jp/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('lake-shikotsu-ice', 'Lake Shikotsu Ice Festival', '千歳・支笏湖氷濤まつり', 'Chitose', 'Hokkaido', 'hokkaido', 2, '02-01', '02-24', '["02-08"]', '["snow","lantern"]', 'Ice sculptures illuminated in vivid colors along the shores of crystal-clear Lake Shikotsu. The natural ice formations are sprayed from the lake water.', '支笏湖の湖水を使った氷像がライトアップされる冬の祭典。', 250000, 'New Chitose Airport, 40 min bus', 42.7900, 141.3486, 'Night illumination is the main draw. Weekday evenings are less crowded.', 'https://hyoutou-special.asia/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('okayama-hadaka', 'Okayama Saidaiji Eyo', '西大寺会陽', 'Okayama', 'Okayama', 'chugoku', 2, '02-15', '02-15', '["02-15"]', '["traditional"]', 'Ten thousand men in loincloths scramble in darkness to grab sacred sticks thrown by a priest. One of Japan''s most famous naked festivals.', '一万人の裸の男が宝木を奪い合う西大寺会陽。500年以上の歴史。', 100000, 'JR Saidaiji Station, 10 min walk', 34.6661, 134.0247, 'The main scramble happens around midnight. Very intense atmosphere.', 'https://www.saidaiji.jp/', 1, '2026-03-29T00:00:00Z');

