INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('tokushima-hina-nagashi', 'Hina Nagashi Doll Floating', '雛流し', 'Tokushima', 'Tokushima', 'shikoku', 3, '03-03', '03-03', '["03-03"]', '["traditional"]', 'Paper hina dolls are floated down the river to carry away bad luck and impurities. A beautiful and poignant Hinamatsuri tradition.', '紙のひな人形を川に流して厄を払う伝統行事。', 3000, 'JR Tokushima Station', 34.0658, 134.5593, 'Arrive in the morning to see the ceremony. Very photogenic.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('tagata-honen-matsuri', 'Tagata Jinja Honen Matsuri', '田県神社豊年祭', 'Komaki', 'Aichi', 'chubu', 3, '03-15', '03-15', '["03-15"]', '["traditional"]', 'A fertility festival famous for its large wooden phallus paraded through the streets. Sake is liberally distributed and the atmosphere is festive and humorous.', '大男茎形を神輿に載せて練り歩く豊年祈願の奇祭。', 50000, 'Meitetsu Tagata-jinja-mae Station', 35.2928, 136.9267, 'Very popular with international visitors. Sake is free and flowing.', 'https://www.tagatajinja.com/', 1, '2026-03-29T00:00:00Z');

