INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('oita-taketa-chikuraku', 'Taketa Bamboo Lantern Festival', '竹楽', 'Taketa', 'Oita', 'kyushu', 11, '11-14', '11-16', '["11-15"]', '["lantern"]', 'Over 20,000 bamboo lanterns illuminate the streets and ruins of this historic castle town. A hauntingly beautiful autumn event.', '約2万本の竹灯籠が城下町竹田の街並みを幻想的に照らす。', 50000, 'JR Bungo-Taketa Station', 32.9725, 131.3933, 'The lanterns against the stone walls of the old town are incredibly atmospheric.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('korankei-momiji', 'Korankei Autumn Foliage', '香嵐渓もみじまつり', 'Toyota', 'Aichi', 'chubu', 11, '11-01', '11-30', '["11-15"]', '["autumn"]', 'Over 4,000 maple trees along the Tomoe River create one of Japan''s most famous autumn foliage spots. Evening illumination is spectacular.', '約4,000本のもみじが巴川沿いに紅葉する東海随一の名所。', 400000, 'Meitetsu Toyota City Station, bus 1 hour', 35.1233, 137.3144, 'Peak foliage usually mid-November. Evening light-up is magical.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
