VALUES ('kobe-luminarie', 'Kobe Luminarie', '神戸ルミナリエ', 'Kobe', 'Hyogo', 'kansai', 12, '12-06', '12-15', '["12-06"]', '["lantern","modern"]', 'A stunning light festival featuring Italian-designed illuminated arches. Originally started to commemorate the 1995 Great Hanshin Earthquake.', '阪神大震災の鎮魂のイルミネーション。イタリア人芸術家の光の彫刻。', 3500000, 'JR Motomachi Station', 34.6900, 135.1861, 'Extremely crowded on weekends. Weeknight visits recommended.', 'https://www.kobe-luminarie.jp/', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('namahage', 'Namahage Sedo Festival', 'なまはげ柴灯まつり', 'Oga', 'Akita', 'tohoku', 12, '12-31', '12-31', '["12-31"]', '["traditional","fire"]', 'Fearsome Namahage demons visit homes on New Year''s Eve to scare lazy children and warn against slothfulness. A UNESCO Intangible Cultural Heritage.', '大晦日に恐ろしいなまはげが家々を訪問。ユネスコ無形文化遺産。', 30000, 'JR Hadachi Station, taxi to Oga', 39.9389, 139.8422, 'Sedo Festival in February is easier to attend for tourists. New Year event is traditional.', '', 1, '2026-03-29T00:00:00Z');

INSERT OR IGNORE INTO matsuri (id, name_en, name_ja, city, prefecture, region, month, date_start, date_end, highlight_dates, category, description_en, description_ja, estimated_visitors, access, latitude, longitude, tips_en, official_url, is_active, updated_at)
VALUES ('toshikoshi-joya', 'Joya no Kane New Year Bell Ringing', '除夜の鐘', 'Kyoto', 'Kyoto', 'kansai', 12, '12-31', '12-31', '["12-31"]', '["traditional"]', 'Buddhist temple bells are rung 108 times at midnight on New Year''s Eve, symbolizing purification from worldly desires. Chion-in has the largest bell.', '大晦日に寺院の鐘を108回撞く。知恩院の鐘が日本最大。', 500000, 'Kyoto City Bus to various temples', 35.0061, 135.7830, 'Chion-in, Kiyomizu-dera, and Todai-ji in Nara are the most popular. Arrive before 11 PM.', '', 1, '2026-03-29T00:00:00Z');

