VALUES ('sapporo-white-illumination', 'Sapporo White Illumination', 'さっぽろホワイトイルミネーション', 'Sapporo', 'Hokkaido', 'hokkaido', 12, '12-01', '12-25', '["12-23"]', '["lantern","modern","snow"]', 'The original illumination event in Japan, started in 1981. LED lights and snow create a magical winter wonderland in Odori Park.', '日本初のイルミネーションイベント。雪と光のコラボレーション。', 2000000, 'JR Sapporo Station or Odori Station', 43.0590, 141.3545, 'Best when fresh snow covers the ground. Combine with Christmas market.', 'https://white-illumination.jp/', 1, '2026-03-29T00:00:00Z');

